import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../secret_file.txt";
        String directory = "/path/to/directory/";

        try {
            Path resolvedPath = Paths.get(directory).resolve(userInput).normalize();
            if (!resolvedPath.startsWith(Paths.get(directory))) {
                System.out.println("Access to file outside directory is not allowed.");
                return;
            }

            File file = resolvedPath.toFile();
            byte[] fileData = Files.readAllBytes(file.toPath());
            System.out.println("File contents: " + new String(fileData));
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

